localparam GOT_1 = 4'b0001;
localparam GOT_11 = 4'b0010;
localparam GOT_110 = 4'b0011;
localparam GOT_1101 = 4'b0100;

always @(posedge clk)
begin
  if(reset)
  begin
    state <= IDLE;
    start_shifting <= 0;
  end
  else
  begin
    case(state)
      IDLE:
      begin
        if(data)
          state <= GOT_1;
        else
          state <= IDLE;
      end
      GOT_1:
      begin
        if(data)
          state <= GOT_11;
        else
          state <= IDLE;
      end
      GOT_11:
      begin
        if(!data)
          state <= GOT_110;
        else
          state <= GOT_1;
      end
      GOT_110:
      begin
        if(data)
          state <= GOT_1101;
        else
          state <= IDLE;
      end
      GOT_1101:
      begin
        start_shifting <= 1;
      end
      default:
      begin
        state <= IDLE;
      end
    endcase
  end
end

