                    state <= 1;
                    walk_left <= 0;
                    walk_right <= 1;
                end
                else
                begin
                    walk_left <= 1;
                    walk_right <= 0;
                end
            end
            1: // walking right
            begin
                if (bump_right)
                begin
                    state <= 0;
                    walk_left <= 1;
                    walk_right <= 0;
                end
