module TopModule(
    input clk,
    input reset,
    input ena,
    output pm,
    output [7:0] hh,
    output [7:0] mm,
    output [7:0] ss
);

reg [7:0] hh_reg;
reg [7:0] mm_reg;
reg [7:0] ss_reg;
reg pm_reg;

assign pm = pm_reg;
assign hh = hh_reg;
assign mm = mm_reg;
assign ss = ss_reg;

always @(posedge clk) begin
    if (reset) begin
        hh_reg <= 8'b0001_0010; // 12 in BCD
        mm_reg <= 8'b0000_0000; // 00 in BCD
        ss_reg <= 8'b0000_0000; // 00 in BCD
        pm_reg <= 1'b0; // AM
    end else if (ena) begin
        if (ss_reg == 8'b0000_0101) begin // 59 in BCD
            ss_reg <= 8'b0000_0000; // 00 in BCD
            if (mm_reg == 8'b0000_1001) begin // 59 in BCD
                mm_reg <= 8'b0000_0000; // 00 in BCD
                if (hh_reg == 8'b0001_0010) begin // 12 in BCD
                    hh_reg <= 8'b0001_0001; // 01 in BCD
                    pm_reg <= ~pm_reg; // toggle AM/PM
                end else if (hh_reg == 8'b0000_1000) begin // 08 in BCD (8 AM)
                    hh_reg <= 8'b0001_0010; // 12 in BCD
                end else if (hh_reg == 8'b0001_0000) begin // 09 in BCD (9 AM)
                    hh_reg <= 8'b0001_0001; // 01 in BCD (1 PM)
                    pm_reg <= 1'b1; // PM
                end else begin
                    hh_reg <= hh_reg + 1;
                end
            end else begin
                mm_reg <= mm_reg + 1;
            end
        end else begin
            ss_reg <= ss_reg + 1;
        end
    end
end

endmodule

