output [7:0] hh;
output [7:0] mm;
output [7:0] ss;

reg [7:0] hh_reg;
reg [7:0] mm_reg;
reg [7:0] ss_reg;
reg pm_reg;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        hh_reg <= 8'd1;
        mm_reg <= 8'd0;
        ss_reg <= 8'd0;
        pm_reg <= 1'b0;
    end else if (ena) begin
        if (ss_reg == 8'd59) begin
            ss_reg <= 8'd0;
            if (mm_reg == 8'd59) begin
                mm_reg <= 8'd0;
                if (hh_reg == 8'd12) begin
                    hh_reg <= 8'd1;
                    pm_reg <= ~pm_reg;
                end else if (hh_reg == 8'd12 - 1) begin
                    hh_reg <= 8'd12;
                end else begin
                    hh_reg <= hh_reg + 8'd1;
                end
            end else begin
                mm_reg <= mm_reg + 8'd1;
            end
        end else begin
            ss_reg <= ss_reg + 8'd1;
        end
    end
end

assign hh = hh_reg;
assign mm = mm_reg;
assign ss = ss_reg;
assign pm = pm_reg;

endmodule

`timescale 1ps/1ps
module TopModule(clk, reset, ena, pm, hh, mm, ss);
    input clk, reset, ena;
    output pm;
    output [7:0] hh, mm, ss;
    reg pm;
    reg [3:0] h, m, s;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            h <= 1; // 1 is 0001 in BCD, representing 12:00 AM
            m <= 0;
            s <= 0;
            pm <= 0;
        end else if (ena) begin
            if (s == 9'd59) begin
                s <= 0;
                if (m == 9'd59) begin
                    m <= 0;
                    if (h == 12) begin // 12 is represented as 1100 in 4-bit BCD
                        h <= 1; // 1 is 0001 in BCD
                        pm <= ~pm;
                    end else begin
                        h <= h + 1;
                    end
                end else begin
                    m <= m + 1;
                end
            end else begin
                s <= s + 1;
            end
        end
    end

    assign hh = {4'b0000, h}; // BCD representation
    assign mm = {4'b0000, m};
    assign ss = {4'b0000, s};
    assign pm = (h[3]); // pm is high when h is greater than or equal to 8 (i.e., 1000 in BCD)
endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input areset,
    input bump_left,
    input bump_right,
    input ground,
    output walk_left,
    output walk_right,
    output aaah
);

reg walk_left_reg;
reg walk_right_reg;
reg aaah_reg;
reg direction;

always @(posedge clk or posedge areset) begin
    if (areset) begin
        walk_left_reg <= 1'b1;
        walk_right_reg <= 1'b0;
        aaah_reg <= 1'b0;
        direction <= 1'b1;
    end else begin
        if (!ground) begin
            walk_left_reg <= 1'b0;
            walk_right_reg <= 1'b0;
            aaah_reg <= 1'b1;
        end else if (ground && !aaah_reg) begin
            if (bump_left && bump_right) begin
                direction <= ~direction;
            end else if (bump_left) begin
                direction <= 1'b0;
            end else if (bump_right) begin
                direction <= 1'b1;
            end
            walk_left_reg <= direction;
            walk_right_reg <= ~direction;
            aaah_reg <= 1'b0;
        end else begin
            walk_left_reg <= direction;
            walk_right_reg <= ~direction;
            aaah_reg <= 1'b0;
        end
    end
end

assign walk_left = walk_left_reg;
assign walk_right = walk_right_reg;
assign aaah = aaah_reg;

endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input areset,
    input bump_left,
    input bump_right,
    input ground,
    output reg walk_left,
    output reg walk_right,
    output reg aaah
);

reg state;
reg next_state;

always @(posedge clk or posedge areset) begin
    if (areset) begin
        state <= 0;
        walk_left <= 1;
        walk_right <= 0;
    end else begin
        state <= next_state;
    end
end

always @(*) begin
    if (ground) begin
        aaah = 0;
        case (state)
            0: begin
                walk_left = 1;
                walk_right = 0;
                if (bump_left) next_state = 1;
                else next_state = 0;
            end
            1: begin
                walk_left = 0;
                walk_right = 1;
                if (bump_right) next_state = 0;
                else next_state = 1;
            end
        endcase
    end else begin
        aaah = 1;
        next_state = state;
    end
end

endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input areset,
    input bump_left,
    input bump_right,
    input ground,
    output reg walk_left,
    output reg walk_right,
    output reg aaah
);

reg state;
reg prev_ground;

always @(posedge clk or posedge areset) begin
    if (areset) begin
        state <= 0;
        prev_ground <= 1;
        walk_left <= 1;
        walk_right <= 0;
        aaah <= 0;
    end else begin
        if (prev_ground && !ground) begin
            prev_ground <= 0;
            walk_left <= 0;
            walk_right <= 0;
            aaah <= 1;
        end else if (!prev_ground && ground) begin
            prev_ground <= 1;
            aaah <= 0;
            if (state) begin
                walk_left <= 1;
                walk_right <= 0;
            end else begin
                walk_left <= 0;
                walk_right <= 1;
            end
        end else if (prev_ground) begin
            if (bump_left && bump_right) begin
                state <= ~state;
            end else if (bump_left) begin
                state <= 0;
            end else if (bump_right) begin
                state <= 1;
            end
            if (state) begin
                walk_left <= 1;
                walk_right <= 0;
            end else begin
                walk_left <= 0;
                walk_right <= 1;
            end
        end
    end
end

endmodule

