);

assign next_state[0] = (~in & (state[0] | state[1] | state[2] | state[3] | state[4] | state[5] | state[6] | state[7] | state[8] | state[9])) ? 1'b1 : 1'b0;
assign next_state[1] = (in & (state[0] | state[8] | state[9])) ? 1'b1 : 1'b0;
assign next_state[2] = (in & state[1]) ? 1'b1 : 1'b0;
assign next_state[3] = (in & state[2]) ? 1'b1 : 1'b0;
assign next_state[4] = (in & state[3]) ? 1'b1 : 1'b0;
assign next_state[5] = (in & state[4]) ? 1'b1 : 1'b0;
