assign next_state[8] = (~in & state[5]) ? 1'b1 : 1'b0;
assign next_state[9] = (~in & state[6]) ? 1'b1 : 1'b0;
assign out1 = (state[7] | state[8] | state[9]) ? 1'b1 : 1'b0;
