`timescale 1ps/1ps
module TopModule(
    input clk,
    input load,
    input [255:0] data,
    output reg [255:0] q
);

reg [255:0] next_q;

always @(posedge clk) begin
    if (load) begin
        q <= data;
    end else begin
        q <= next_q;
    end
end

always @(*) begin
    next_q = 256'b0;
    for (int i = 0; i < 16; i = i + 1) begin
        for (int j = 0; j < 16; j = j + 1) begin
            reg [2:0] neighbors;
            neighbors = 3'b0;
            for (int x = -1; x <= 1; x = x + 1) begin
                for (int y = -1; y <= 1; y = y + 1) begin
                    if ((x == 0) && (y == 0)) begin
                        // skip self
                    end else begin
                        reg [4:0] ni, nj;
                        ni = (i + x) % 16;
                        nj = (j + y) % 16;
                        if (q[ni*16 + nj] == 1'b1) begin
                            neighbors = neighbors + 1'b1;
                        end
                    end
                end
            end
            case (neighbors)
                3'b000, 3'b001: next_q[i*16 + j] = 1'b0;
                3'b010: next_q[i*16 + j] = q[i*16 + j];
                3'b011: next_q[i*16 + j] = 1'b1;
                default: next_q[i*16 + j] = 1'b0;
            endcase
        end
    end
end

endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input load,
    input [255:0] data,
    output reg [255:0] q
);

reg [255:0] next_q;

always @(posedge clk) begin
    if (load) begin
        q <= data;
    end else begin
        q <= next_q;
    end
end

genvar i;
generate
    for (i = 0; i < 256; i = i + 1) begin
        wire [7:0] neighbors;
        wire [2:0] count;

        // Calculate neighbors
        assign neighbors[0] = q[(i + 1) % 256];
        assign neighbors[1] = q[(i + 16) % 256];
        assign neighbors[2] = q[(i + 17) % 256];
        assign neighbors[3] = q[(i - 1 + 256) % 256];
        assign neighbors[4] = q[(i - 16 + 256) % 256];
        assign neighbors[5] = q[(i - 17 + 256) % 256];
        assign neighbors[6] = q[(i + 15) % 256];
        assign neighbors[7] = q[(i - 15 + 256) % 256];

        // Count neighbors
        assign count[0] = neighbors[0] + neighbors[1] + neighbors[2] + neighbors[3] + neighbors[4] + neighbors[5] + neighbors[6] + neighbors[7];
        assign count[1] = 0;
        assign count[2] = 0;

        // Update cell state
        assign next_q[i] = (count[0] == 3) || (count[0] == 2 && q[i]);
    end
endgenerate

endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input load,
    input [255:0] data,
    output reg [255:0] q
);

reg [255:0] next_q;
reg [255:0] q_reg;

always @(posedge clk) begin
    if (load) begin
        q_reg <= data;
    end else begin
        q_reg <= next_q;
    end
end

genvar i;
generate
    for (i = 0; i < 256; i = i + 1) begin
        wire [7:0] neighbors;
        wire [3:0] count;
        assign neighbors[0] = q_reg[(i + 1) % 256];
        assign neighbors[1] = q_reg[(i + 16) % 256];
        assign neighbors[2] = q_reg[(i + 17) % 256];
        assign neighbors[3] = q_reg[(i - 1 + 256) % 256];
        assign neighbors[4] = q_reg[(i - 16 + 256) % 256];
        assign neighbors[5] = q_reg[(i - 17 + 256) % 256];
        assign neighbors[6] = q_reg[(i + 15) % 256];
        assign neighbors[7] = q_reg[(i - 15 + 256) % 256];
        assign count = neighbors[0] + neighbors[1] + neighbors[2] + neighbors[3] + neighbors[4] + neighbors[5] + neighbors[6] + neighbors[7];
        always @(*) begin
            if (count == 2) begin
                next_q[i] = q_reg[i];
            end else if (count == 3) begin
                next_q[i] = 1'b1;
            end else if (count < 2 || count > 3) begin
                next_q[i] = 1'b0;
            end else begin
                next_q[i] = q_reg[i];
