               COUNT = 4'b0010, 
               WAIT_ACK = 4'b0011,
               PATTERN_DETECT = 4'b0100,
               SHIFT_1 = 4'b0101,
               SHIFT_2 = 4'b0110,
               SHIFT_3 = 4'b0111,
               SHIFT_4 = 4'b1000;

    always @(posedge clk) begin
        if(reset) begin
            state <= IDLE;
            shift_ena <= 0;
            counting <= 0;
            done <= 0;
        end else begin
            case(state)
                IDLE: begin
                    if(data == 1) begin
                        state <= PATTERN_DETECT;
                    end else begin
                        state <= IDLE;
                    end
                    shift_ena <= 0;
                    counting <= 0;
                    done <= 0;
                end
                PATTERN_DETECT: begin
                    if(data == 1) begin
                        state <= PATTERN_DETECT;
                    end else if(data == 0) begin
                        state <= SHIFT_1;
                    end else begin
                        state <= IDLE;
                    end
                    shift_ena <= 0;
                    counting <= 0;
                    done <= 0;
                end
                SHIFT_1: begin
                    if(data == 0) begin
                        state <= SHIFT_2;
                    end else begin
                        state <= IDLE;
                    end
                    shift_ena <= 1;
                    counting <= 0;
                    done <= 0;
                end
                SHIFT_2: begin
                    if(data == 1) begin
                        state <= SHIFT_3;
                    end else begin
                        state <= IDLE;
                    end
                    shift_ena <= 1;
                    counting <= 0;
                    done <= 0;
                end
                SHIFT_3: begin
                    if(data == 0) begin
                        state <= SHIFT_4;
                    end else begin
                        state <= IDLE;
                    end
                    shift_ena <= 1;
                    counting <= 0;
                    done <= 0;
                end
                SHIFT_4: begin
                    if(data == 1) begin
                        state <= COUNT;
                    end else begin
                        state <= IDLE;
                    end
                    shift_ena <= 1;
                    counting <= 0;
                    done <= 0;
                end
                COUNT: begin
                    if(done_counting) begin
                        state <= WAIT_ACK;
                    end else begin
                        state <= COUNT;
                    end
                    shift_ena <= 0;
                    counting <= 1;
                    done <= 0;
                end
                WAIT_ACK: begin
                    if(ack) begin
                        state <= IDLE;
                    end else begin
                        state <= WAIT_ACK;
                    end
                    shift_ena <= 0;
                    counting <= 0;
                    done <= 1;
                end
            endcase
        end
    end
