`timescale 1ps/1ps
module TopModule(
    clk, 
    reset, 
    data, 
    done_counting, 
    ack, 
    shift_ena, 
    counting, 
    done
);
input clk;
input reset;
input data;
input done_counting;
input ack;
output reg shift_ena;
output reg counting;
output reg done;
reg [3:0] state;
reg [3:0] next_state;
reg [3:0] shift_counter;
reg [3:0] pattern_counter;
parameter IDLE = 4'd0, DETECT_PATTERN = 4'd1, SHIFT = 4'd2, COUNT = 4'd3, DONE = 4'd4;

always @ (posedge clk) begin
    if (reset) begin
        state <= IDLE;
        shift_counter <= 4'd0;
        pattern_counter <= 4'd0;
        shift_ena <= 1'b0;
        counting <= 1'b0;
        done <= 1'b0;
    end else begin
        state <= next_state;
        if (state == SHIFT) begin
            shift_counter <= shift_counter + 1;
        end else begin
            shift_counter <= 4'd0;
        end
        if (state == DETECT_PATTERN) begin
            if (data == 1'b1 && pattern_counter == 4'd0) begin
                pattern_counter <= pattern_counter + 1;
            end else if (data == 1'b0 && pattern_counter == 4'd1) begin
                pattern_counter <= pattern_counter + 1;
            end else if (data == 1'b1 && pattern_counter == 4'd2) begin
                pattern_counter <= pattern_counter + 1;
            end else if (data == 1'b0 && pattern_counter == 4'd3) begin
                pattern_counter <= pattern_counter + 1;
            end else begin
                pattern_counter <= 4'd0;
            end
        end else begin
            pattern_counter <= 4'd0;
        end
    end
end

always @ (*) begin
    case (state)
        IDLE: begin
            if (data == 1'b1) begin
                next_state = DETECT_PATTERN;
            end else begin
                next_state = IDLE;
            end
        end
        DETECT_PATTERN: begin
            if (pattern_counter == 4'd4) begin
                next_state = SHIFT;
            end else if (data == 1'b1 && pattern_counter == 4'd0) begin
                next_state = DETECT_PATTERN;
            end else if (data == 1'b0 && pattern_counter == 4'd1) begin
                next_state = DETECT_PATTERN;
            end else if (data == 1'b1 && pattern_counter == 4'd2) begin
                next_state = DETECT_PATTERN;
            end else if (data == 1'b0 && pattern_counter == 4'd3) begin
                next_state = DETECT_PATTERN;
            end else begin
                next_state = IDLE;
            end
        end
        SHIFT: begin
            if (shift_counter == 4'd4) begin
                next_state = COUNT;
            end else begin
                next_state = SHIFT;
            end
        end
        COUNT: begin
            if (done_counting) begin
                next_state = DONE;
            end else begin
                next_state = COUNT;
            end
        end
        DONE: begin
            if (ack) begin
                next_state = IDLE;
            end else begin
                next_state = DONE;
            end
        end
    endcase
end

always @ (*) begin
    case (state)
        IDLE: begin
            shift_ena = 1'b0;
            counting = 1'b0;
            done = 1'b0;
        end
        DETECT_PATTERN: begin
            shift_ena = 1'b0;
            counting = 1'b0;
            done = 1'b0;
        end
        SHIFT: begin
            shift_ena = 1'b1;
            counting = 1'b0;
            done = 1'b0;
        end
        COUNT: begin
            shift_ena = 1'b0;
            counting = 1'b1;
            done = 1'b0;
        end
        DONE: begin
            shift_ena = 1'b0;
            counting = 1'b0;
            done = 1'b1;
        end
    endcase
end
endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input areset,
    input bump_left,
    input bump_right,
    input ground,
    input dig,
    output walk_left,
    output walk_right,
    output aaah,
    output digging
);

reg [1:0] state;
reg [1:0] next_state;
reg walk_left_reg;
reg walk_right_reg;
reg aaah_reg;
reg digging_reg;

assign walk_left = walk_left_reg;
assign walk_right = walk_right_reg;
assign aaah = aaah_reg;
assign digging = digging_reg;

always @(*) begin
    case (state)
        2'b00: begin // walking left
            if (!ground) begin
                next_state = 2'b01; // falling
            end else if (dig) begin
                next_state = 2'b10; // digging
            end else if (bump_left) begin
                next_state = 2'b00; // switch to right
            end else if (bump_right) begin
                next_state = 2'b00; // switch to right
            end else begin
                next_state = 2'b00; // stay left
            end
        end
        2'b01: begin // falling
            if (ground) begin
                next_state = 2'b00; // resume walking left
            end else begin
                next_state = 2'b01; // keep falling
            end
        end
        2'b10: begin // digging
            if (!ground) begin
                next_state = 2'b01; // falling
            end else begin
                next_state = 2'b10; // keep digging
            end
        end
        2'b11: begin // walking right
            if (!ground) begin
                next_state = 2'b01; // falling
            end else if (dig) begin
                next_state = 2'b10; // digging
            end else if (bump_left) begin
                next_state = 2'b11; // switch to left
            end else if (bump_right) begin
                next_state = 2'b11; // switch to left
            end else begin
                next_state = 2'b11; // stay right
            end
        end
        default: next_state = 2'b00;
    endcase
end

always @(posedge clk or posedge areset) begin
    if (areset) begin
        state <= 2'b00;
        walk_left_reg <= 1'b1;
        walk_right_reg <= 1'b0;
        aaah_reg <= 1'b0;
        digging_reg <= 1'b0;
    end else begin
        state <= next_state;
        case (next_state)
            2'b00: begin
                walk_left_reg <= 1'b1;
                walk_right_reg <= 1'b0;
                aaah_reg <= 1'b0;
                digging_reg <= 1'b0;
            end
            2'b01: begin
                walk_left_reg <= 1'b0;
                walk_right_reg <= 1'b0;
                aaah_reg <= 1'b1;
                digging_reg <= 1'b0;
            end
            2'b10: begin
                walk_left_reg <= 1'b0;
                walk_right_reg <= 1'b0;
                aaah_reg <= 1'b0;
                digging_reg <= 1'b1;
            end
            2'b11: begin
                walk_left_reg <= 1'b0;
                walk_right_reg <= 1'b1;
                aaah_reg <= 1'b0;
                digging_reg <= 1'b0;
            end
            default: begin
                walk_left_reg <= 1'b0;
                walk_right_reg <= 1'b0;
                aaah_reg <= 1'b0;
                digging_reg <= 1'b0;
            end
        endcase
    end
end

endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input areset,
    input bump_left,
    input bump_right,
    input ground,
    input dig,
    output reg walk_left,
    output reg walk_right,
    output reg aaah,
    output reg digging
);

reg state;
reg direction;
reg was_digging;

always @(posedge clk or posedge areset) begin
    if (areset) begin
        state <= 0;
        direction <= 1;
        was_digging <= 0;
        walk_left <= 1;
        walk_right <= 0;
        aaah <= 0;
        digging <= 0;
    end else begin
        case (state)
            0: begin // walking
                if (!ground) begin
                    state <= 1;
                    walk_left <= 0;
                    walk_right <= 0;
                    aaah <= 1;
                    digging <= 0;
                end else if (dig) begin
                    state <= 2;
                    walk_left <= 0;
                    walk_right <= 0;
                    aaah <= 0;
                    digging <= 1;
                end else if (bump_left && bump_right) begin
                    direction <= !direction;
                end else if (bump_left) begin
                    direction <= 0;
                end else if (bump_right) begin
                    direction <= 1;
                end
                if (direction) begin
                    walk_left <= 1;
                    walk_right <= 0;
                end else begin
                    walk_left <= 0;
                    walk_right <= 1;
                end
            end
            1: begin // falling
                if (ground) begin
                    state <= 0;
                    walk_left <= 0;
                    walk_right <= 0;
                    aaah <= 0;
                    digging <= 0;
                    if (direction) begin
                        walk_left <= 1;
                        walk_right <= 0;
                    end else begin
                        walk_left <= 0;
                        walk_right <= 1;
                    end
                end
            end
            2: begin // digging
                if (!ground) begin
                    state <= 1;
                    walk_left <= 0;
                    walk_right <= 0;
                    aaah <= 1;
                    digging <= 0;
                end
            end
        endcase
    end
end

endmodule

