`timescale 1ps/1ps
module TopModule(
    input clk,
    input areset,
    input predict_valid,
    input [6:0] predict_pc,
    output reg predict_taken,
    output reg [6:0] predict_history,
    input train_valid,
    input train_taken,
    input train_mispredicted,
    input [6:0] train_history,
    input [6:0] train_pc
);

reg [6:0] global_history;
reg [7:0] pht [127:0];

always @(posedge clk or posedge areset)
begin
    if (areset)
    begin
        global_history <= 0;
        for (int i = 0; i < 128; i++)
            pht[i] <= 2'b00;
    end
    else
    begin
        if (train_valid)
        begin
            if (train_mispredicted)
                global_history <= train_history;
            else
                global_history <= {global_history[5:0], train_taken};
        end
        else if (predict_valid)
            global_history <= {global_history[5:0], predict_taken};
    end
end

always @(posedge clk)
begin
    if (train_valid)
    begin
        reg [6:0] index;
        index = (train_pc ^ train_history);
        index = index[6:0];
        if (index >= 128)
            index = 0;
        if (train_taken && train_mispredicted && pht[index] != 2'b11)
            pht[index] <= pht[index] + 1;
        else if (!train_taken && train_mispredicted && pht[index] != 2'b00)
            pht[index] <= pht[index] - 1;
    end
end

always @(*)
begin
    reg [6:0] index;
    index = (predict_pc ^ global_history);
    index = index[6:0];
    if (index >= 128)
        index = 0;
    predict_taken = (pht[index] == 2'b11 || pht[index] == 2'b10);
    predict_history = global_history;
end

endmodule

