module TopModule(
    input clk,
    input areset,
    input predict_valid,
    input [6:0] predict_pc,
    output predict_taken,
    output [6:0] predict_history,
    input train_valid,
    input train_taken,
    input train_mispredicted,
    input [6:0] train_history,
    input [6:0] train_pc
);

reg [6:0] history_reg;
reg [6:0] history_reg_next;
reg [7:0] pht [127:0];

always @(*) begin
    history_reg_next = history_reg;
    if (predict_valid) begin
        history_reg_next = {history_reg[5:0], predict_taken};
    end
    if (train_valid && train_mispredicted) begin
        history_reg_next = train_history;
    end
end

always @(posedge clk or posedge areset) begin
    if (areset) begin
        history_reg <= 7'b0;
        for (int i = 0; i < 128; i++) begin
            pht[i] <= 2'b0;
        end
    end else begin
        history_reg <= history_reg_next;
        if (train_valid) begin
            pht[{predict_pc[6:0] ^ history_reg[6:0]}[6:0]] <= (train_taken) ? (pht[{predict_pc[6:0] ^ history_reg[6:0]}[6:0]] == 2'b11 ? 2'b11 : pht[{predict_pc[6:0] ^ history_reg[6:0]}[6:0]] + 1'b1) : (pht[{predict_pc[6:0] ^ history_reg[6:0]}[6:0]] == 2'b00 ? 2'b00 : pht[{predict_pc[6:0] ^ history_reg[6:0]}[6:0]] - 1'b1);
        end
    end
end

assign predict_taken = (pht[{predict_pc[6:0] ^ history_reg[6:0]}[6:0]] >= 2'b10);
assign predict_history = history_reg;

endmodule

