module TopModule(
    input clk,
    input areset,
    input bump_left,
    input bump_right,
    input ground,
    input dig,
    output walk_left,
    output walk_right,
    output aaah,
    output digging
);

reg [1:0] state;
reg [4:0] fall_count;
reg walk_dir;
reg digging_reg;

assign walk_left = walk_dir && !aaah && !digging_reg;
assign walk_right = !walk_dir && !aaah && !digging_reg;
assign aaah = state == 2'b01;
assign digging = digging_reg;

always @(posedge clk or posedge areset)
begin
    if (areset)
    begin
        state <= 2'b00;
        fall_count <= 5'b0;
        walk_dir <= 1'b0;
        digging_reg <= 1'b0;
    end
    else
    begin
        case (state)
            2'b00: // walking
            begin
                if (!ground)
                begin
                    state <= 2'b01;
                    fall_count <= 1;
                end
                else if (dig)
                begin
                    state <= 2'b10;
                    digging_reg <= 1'b1;
                end
                else if (bump_left)
                begin
                    walk_dir <= 1'b1;
                end
                else if (bump_right)
                begin
                    walk_dir <= 1'b0;
                end
            end
            2'b01: // falling
            begin
                fall_count <= fall_count + 1;
                if (ground)
                begin
                    if (fall_count > 5'b10100)
                    begin
                        state <= 2'b11;
                    end
                    else
                    begin
                        state <= 2'b00;
                    end
                    fall_count <= 5'b0;
                end
            end
            2'b10: // digging
            begin
                if (!ground)
                begin
                    state <= 2'b01;
                    fall_count <= 1;
                    digging_reg <= 1'b0;
                end
            end
            2'b11: // splattered
            begin
                walk_dir <= 1'b0;
                digging_reg <= 1'b0;
            end
        endcase
    end
end

