always @(posedge clk or posedge areset) begin
    if (areset) begin
        walk_dir <= 1'b0;
        digging_state <= 1'b0;
        fall_counter <= 5'b0;
        current_state <= 1'b0;
    end else begin
        walk_dir <= next_state ? 1'b1 : 1'b0;
        digging_state <= (digging_state && ground) || (dig && ground && !fall_counter[4]);
        fall_counter <= (ground && !fall_counter[4]) ? 5'b0 : (fall_counter + 1'b1);
        current_state <= next_state;
    end
end

assign next_state = (!ground && !fall_counter[4]) ? walk_dir : 
                    (bump_left && bump_right) ? !walk_dir : 
                    (bump_left) ? 1'b1 : 
                    (bump_right) ? 1'b0 : 
                    walk_dir;

assign walk_left = (current_state == 1'b0) && !digging_state && ground && !fall_counter[4];
assign walk_right = (current_state == 1'b1) && !digging_state && ground && !fall_counter[4];
assign aaah = !ground;
assign digging = digging_state;

endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input areset,
    input bump_left,
    input bump_right,
    input ground,
    input dig,
    output reg walk_left,
    output reg walk_right,
    output reg aaah,
    output reg digging
);

reg[4:0] fall_counter;
reg[1:0] state;
reg direction;

always @(posedge clk or posedge areset)
begin
    if (areset)
    begin
        walk_left <= 1;
        walk_right <= 0;
        aaah <= 0;
        digging <= 0;
        fall_counter <= 0;
        state <= 0;
        direction <= 1;
    end
    else
    begin
        case (state)
            0: // walking
            begin
                if (!ground)
                begin
                    state <= 1;
                    fall_counter <= 1;
                    walk_left <= 0;
                    walk_right <= 0;
                    aaah <= 1;
                    digging <= 0;
                end
                else if (dig)
                begin
                    state <= 2;
                    digging <= 1;
                    walk_left <= 0;
                    walk_right <= 0;
                    aaah <= 0;
                end
                else if (bump_left && bump_right)
                begin
                    direction <= !direction;
                end
                else if (bump_left)
                begin
                    direction <= 0;
                end
                else if (bump_right)
                begin
                    direction <= 1;
                end
                if (direction)
                begin
                    walk_left <= 0;
                    walk_right <= 1;
                end
                else
                begin
                    walk_left <= 1;
                    walk_right <= 0;
                end
            end
            1: // falling
            begin
                fall_counter <= fall_counter + 1;
                if (ground)
                begin
                    if (fall_counter > 20)
                    begin
                        state <= 3;
                        walk_left <= 0;
                        walk_right <= 0;
                        aaah <= 0;
                        digging <= 0;
                    end
                    else
                    begin
                        state <= 0;
                        aaah <= 0;
                        if (direction)
                        begin
                            walk_left <= 0;
                            walk_right <= 1;
                        end
                        else
                        begin
                            walk_left <= 1;
                            walk_right <= 0;
                        end
                    end
                end
                else
                begin
                    walk_left <= 0;
                    walk_right <= 0;
                end
            end
            2: // digging
            begin
                if (!ground)
                begin
                    state <= 1;
                    fall_counter <= 1;
                    walk_left <= 0;
                    walk_right <= 0;
                    aaah <= 1;
                    digging <= 0;
                end
                else
                begin
                    digging <= 1;
                    if (direction)
                    begin
                        walk_left <= 0;
                        walk_right <= 1;
                    end
                    else
                    begin
                        walk_left <= 1;
                        walk_right <= 0;
                    end
                end
            end
            3: // splattered
            begin
                walk_left <= 0;
                walk_right <= 0;
                aaah <= 0;
                digging <= 0;
            end
        endcase
    end
end
endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input reset,
    input data,
    output [3:0] count,
    output reg counting,
    output reg done,
    input ack
);

reg [3:0] delay;
reg [9:0] counter;
reg [3:0] remaining;
reg [3:0] shift_reg;
reg start;

always @(posedge clk) begin
    if (reset) begin
        counting <= 0;
        done <= 0;
        start <= 0;
        shift_reg <= 0;
        counter <= 0;
        remaining <= 0;
        delay <= 0;
    end else if (start) begin
        if (counter < (delay + 1) * 1000) begin
            counting <= 1;
            counter <= counter + 1;
            if (counter % 1000 == 0) begin
                remaining <= remaining - 1;
            end
        end else begin
            counting <= 0;
            done <= 1;
            if (ack) begin
                start <= 0;
                done <= 0;
                counter <= 0;
                remaining <= 0;
                delay <= 0;
            end
        end
    end else begin
        if (shift_reg == 4'b1101) begin
            start <= 1;
            remaining <= delay;
        end else if (shift_reg[3:1] == 3'b110) begin
            shift_reg <= {data, shift_reg[3:1]};
        end else begin
            shift_reg <= {data, shift_reg[3:1]};
        end
        if (start && shift_reg == 4'b1101) begin
            delay <= {data, shift_reg[2:0]};
        end
    end
end

assign count = remaining;

endmodule

`timescale 1ps/1ps
module TopModule(
    input clk,
    input reset,
    input data,
    output reg [3:0] count,
    output reg counting,
    output reg done,
    input ack
);

reg [3:0] delay;
reg [3:0] counter;
reg [9:0] timer;
reg [3:0] state;

always @ (posedge clk) begin
    if(reset == 1) begin
        state <= 0;
        counting <= 0;
        done <= 0;
        timer <= 0;
        counter <= 0;
        delay <= 0;
        count <= 0;
    end else begin
        case(state)
            0: begin
                if(data == 1) begin
                    state <= 1;
                end
            end
            1: begin
                if(data == 1) begin
                    state <= 2;
                end else begin
                    state <= 0;
                end
            end
            2: begin
                if(data == 0) begin
                    state <= 3;
                end else begin
                    state <= 0;
                end
            end
            3: begin
                if(data == 1) begin
                    state <= 4;
                    delay[3] <= 1;
                end else begin
                    state <= 0;
                end
            end
            4: begin
                delay[2] <= data;
                state <= 5;
            end
            5: begin
                delay[1] <= data;
                state <= 6;
            end
            6: begin
                delay[0] <= data;
                state <= 7;
                timer <= (delay + 1) * 1000 - 1;
                counting <= 1;
            end
            7: begin
                if(timer == 0) begin
                    state <= 8;
                    counting <= 0;
                end else begin
                    timer <= timer - 1;
                    if(timer % 1000 == 0) begin
                        counter <= counter - 1;
                    end
                    count <= counter;
                end
            end
            8: begin
                done <= 1;
                if(ack == 1) begin
                    state <= 0;
                    done <= 0;
                end
            end
        endcase
    end
end

endmodule

`timescale 1ps/1ps
module TopModule(
    clk, 
    reset, 
    data, 
    count, 
    counting, 
    done, 
    ack
);
input clk;
input reset;
input data;
output [3:0] count;
output counting;
output done;
input ack;

reg [3:0] count_reg;
reg counting_reg;
reg done_reg;
reg [3:0] delay_reg;
reg [11:0] timer_reg;
reg [3:0] shift_reg;
reg start_timer;
reg shift_enable;
reg search_enable;
reg [3:0] pattern_reg;

always @ (posedge clk) begin
    if(reset == 1) begin
        count_reg <= 4'b0000;
        counting_reg <= 1'b0;
        done_reg <= 1'b0;
        delay_reg <= 4'b0000;
        timer_reg <= 12'b0000;
        shift_reg <= 4'b0000;
        start_timer <= 1'b0;
        shift_enable <= 1'b0;
        search_enable <= 1'b1;
        pattern_reg <= 4'b0000;
    end else begin
        if(search_enable == 1'b1) begin
            pattern_reg <= {pattern_reg[2:0], data};
            if(pattern_reg == 4'b1101) begin
                search_enable <= 1'b0;
                shift_enable <= 1'b1;
            end
        end
        if(shift_enable == 1'b1) begin
            shift_reg <= {shift_reg[2:0], data};
            if(shift_reg == 4'b1000) begin
                delay_reg <= shift_reg;
                shift_enable <= 1'b0;
                start_timer <= 1'b1;
            end else if(shift_reg == 4'b0111) begin
                delay_reg <= shift_reg;
                shift_enable <= 1'b0;
                start_timer <= 1'b1;
            end else if(shift_reg == 4'b0110) begin
                delay_reg <= shift_reg;
                shift_enable <= 1'b0;
                start_timer <= 1'b1;
            end else if(shift_reg == 4'b0101) begin
                delay_reg <= shift_reg;
                shift_enable <= 1'b0;
                start_timer <= 1'b1;
            end else if(shift_reg == 4'b0100) begin
                delay_reg <= shift_reg;
                shift_enable <= 1'b0;
                start_timer <= 1'b1;
            end else if(shift_reg == 4'b0011) begin
                delay_reg <= shift_reg;
                shift_enable <= 1'b0;
                start_timer <= 1'b1;
            end else if(shift_reg == 4'b0010) begin
                delay_reg <= shift_reg;
                shift_enable <= 1'b0;
                start_timer <= 1'b1;
            end else if(shift_reg == 4'b0001) begin
                delay_reg <= shift_reg;
                shift_enable <= 1'b0;
                start_timer <= 1'b1;
            end else if(shift_reg == 4'b0000) begin
                delay_reg <= shift_reg;
                shift_enable <= 1'b0;
                start_timer <= 1'b1;
            end
        end
        if(start_timer == 1'b1) begin
            counting_reg <= 1'b1;
            if(timer_reg == ((delay_reg + 1'b1) * 1000) - 1) begin
                timer_reg <= 12'b0000;
                delay_reg <= delay_reg - 1'b1;
                if(delay_reg == 4'b0000) begin
                    start_timer <= 1'b0;
                    done_reg <= 1'b1;
                end
            end else begin
                timer_reg <= timer_reg + 1'b1;
            end
        end
        if(done_reg == 1'b1) begin
            if(ack == 1'b1) begin
                done_reg <= 1'b0;
                counting_reg <= 1'b0;
                search_enable <= 1'b1;
            end
        end
    end
end

assign count = (start_timer == 1'b1) ? delay_reg : 4'b0000;
assign done = done_reg;
assign counting = counting_reg;

endmodule
